typedef struct {
    float weight;
    long  assign;
    float cost;
} Point_Struct;

inline void pgain_core(
    __global const Point_Struct *p,
    __global const float *coord,
    __global float *work_mem,
    __global const int *center_table,
    __global char *switch_membership,
    __local float *x_coord_local,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    const int gid = (int)get_global_id(0);
    const int lid = (int)get_local_id(0);

    if (lid < dim) {
        x_coord_local[lid] = coord[(size_t)lid * (size_t)num + (size_t)x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= num) return;

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[(size_t)d * (size_t)num + (size_t)gid] - x_coord_local[d];
        x_cost += diff * diff;
    }
    x_cost *= p[gid].weight;

    const float current_cost = p[gid].cost;
    const int row_base = gid * (K + 1);

    if (x_cost < current_cost) {
        switch_membership[gid] = '1';
        work_mem[row_base + K] += (x_cost - current_cost);
    } else {
        const int assign = (int)p[gid].assign;
        const int col = center_table[assign];
        work_mem[row_base + col] += (current_cost - x_cost);
    }
}

/* kernel slot 0 (kept for compatibility with existing host-side kernel indexing) */
__kernel void pgain_kernel0(
    __global const Point_Struct *p,
    __global const float *coord,
    __global float *work_mem,
    __global const int *center_table,
    __global char *switch_membership,
    __local float *x_coord_local,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    pgain_core(p, coord, work_mem, center_table, switch_membership,
               x_coord_local, num, dim, x, K);
}

